@IsTest(IsParallel=true)
private class AccountUpdateService_Test {

    private static final String NAMED_CRED_BODY = '{"score": 87}';

    @TestSetup
    static void setupData() {
        // One Account at the bulk-tier threshold so the happy-path branch flips to Enterprise.
        Account a = TestDataFactory.account('Acme Enterprise');
        a.AnnualRevenue = 5000000;
        insert a;
    }

    @IsTest
    static void happy_refreshTier_setsEnterpriseTier() {
        Account seeded = [SELECT Id FROM Account LIMIT 1];
        Test.startTest();
        List<Account> result = AccountUpdateService.refreshTier(new Set<Id>{ seeded.Id });
        Test.stopTest();

        System.assertEquals(1, result.size(), 'refreshTier should return the touched record');
        System.assertEquals('Enterprise', result[0].Tier__c, 'AnnualRevenue >= 1M should map to Enterprise');
    }

    @IsTest
    static void bulk_refreshTier_200Accounts_oneSoqlOneDml() {
        // BulkTestPattern: 200 records, half above the threshold, half below.
        List<Account> accounts = TestDataFactory.accounts(200);
        for (Integer i = 0; i < accounts.size(); i++) {
            accounts[i].AnnualRevenue = (i < 100) ? 2000000 : 50000;
        }
        insert accounts;
        Set<Id> ids = (new Map<Id, Account>(accounts)).keySet();

        Integer soqlBefore = Limits.getQueries();
        Integer dmlBefore = Limits.getDmlStatements();
        Test.startTest();
        AccountUpdateService.refreshTier(ids);
        Test.stopTest();
        Integer soqlAfter = Limits.getQueries();
        Integer dmlAfter = Limits.getDmlStatements();

        System.assertEquals(1, soqlAfter - soqlBefore, 'Bulk path must execute exactly one SOQL');
        System.assertEquals(1, dmlAfter - dmlBefore, 'Bulk path must execute exactly one DML');

        // Spot-check both branches.
        Map<Id, Account> updated = new Map<Id, Account>([SELECT Id, Tier__c FROM Account WHERE Id IN :ids]);
        System.assertEquals('Enterprise', updated.get(accounts[0].Id).Tier__c);
        System.assertEquals('SMB', updated.get(accounts[150].Id).Tier__c);
    }

    @IsTest
    static void runAs_standardUser_respectsSharing() {
        // with-sharing posture — ensure a standard user without record access cannot widen the result set.
        User standardUser = TestUserFactory.standardUser();
        Account other;
        System.runAs(new User(Id = UserInfo.getUserId())) {
            other = TestDataFactory.account('Out-of-share');
            insert other;
        }

        System.runAs(standardUser) {
            List<Account> result = AccountUpdateService.refreshTier(new Set<Id>{ other.Id });
            // with-sharing + WITH SECURITY_ENFORCED: the SOQL returns zero rows, refreshTier returns an empty list, NOT throws.
            System.assertEquals(0, result.size(), 'Standard user should not see the out-of-share Account');
        }
    }

    @IsTest
    static void callout_200OK_returnsBody() {
        Test.setMock(HttpCalloutMock.class, new MockHttpResponseGenerator(200, NAMED_CRED_BODY));
        Account seeded = [SELECT Id FROM Account LIMIT 1];
        Test.startTest();
        String body = AccountUpdateService.fetchExternalScore(seeded.Id);
        Test.stopTest();
        System.assertEquals(NAMED_CRED_BODY, body);
    }

    @IsTest
    static void callout_non200_throws() {
        Test.setMock(HttpCalloutMock.class, new MockHttpResponseGenerator(503, 'unavailable'));
        Account seeded = [SELECT Id FROM Account LIMIT 1];
        try {
            Test.startTest();
            AccountUpdateService.fetchExternalScore(seeded.Id);
            Test.stopTest();
            System.assert(false, 'Expected AccountUpdateException');
        } catch (AccountUpdateService.AccountUpdateException e) {
            System.assert(e.getMessage().contains('503'), 'Exception should surface the upstream status');
        }
    }

    @IsTest
    static void negative_emptyIds_throws() {
        try {
            AccountUpdateService.refreshTier(new Set<Id>());
            System.assert(false, 'Expected AccountUpdateException');
        } catch (AccountUpdateService.AccountUpdateException e) {
            System.assert(e.getMessage().contains('accountIds'));
        }
    }

    @IsTest
    static void negative_nullId_throws() {
        try {
            AccountUpdateService.fetchExternalScore(null);
            System.assert(false, 'Expected AccountUpdateException');
        } catch (AccountUpdateService.AccountUpdateException e) {
            System.assert(e.getMessage().contains('accountId'));
        }
    }
}
